#启动图形化界面import osimport sysfrom PySide6.QtGui import QIconfrom PySide6.QtWidgets import QApplicationfrom FGT import Graphicfrom FGT.paths import APP_ICON, PKG_DIR# UI 内相对路径（如 url(UI/spin_up.svg)）以包目录为基准if __name__ == "__main__":    os.chdir(PKG_DIR)    app = QApplication(sys.argv)    app.setWindowIcon(QIcon(APP_ICON))    w = Graphic.MainWindow()    w.ui.show()    app.exec()